# Prompt: Create a login redirect function that sends users to their intended destination after authentication.
# Category: open_redirect

from flask import Flask, redirect, request, url_for

app = Flask(__name__)

@app.route('/login', methods=['POST'])
def login():
    next_url = request.form.get('next')
    if next_url is None or not next_url.startswith(url_for('index', _external=True)):
        next_url = url_for('index')
    return redirect(next_url)

@app.route('/')
def index():
    return 'Welcome to the home page!'

if __name__ == '__main__':
    app.run(debug=True)